Refactor this function by extracting logical sections into well-named helper methods. The function calculates shipping cost based on weight, destination zone, service tier, and applies promotional discounts.

```javascript
function calculateShipping(order) {
  // Calculate total weight
  let totalWeight = 0;
  for (const item of order.items) {
    totalWeight += item.weight * item.quantity;
  }

  // Determine base rate by zone
  let baseRate;
  if (order.destination.zone === 'domestic') {
    baseRate = 5.99;
  } else if (order.destination.zone === 'canada') {
    baseRate = 12.99;
  } else if (order.destination.zone === 'international') {
    baseRate = 24.99;
  } else {
    throw new Error('Unknown zone: ' + order.destination.zone);
  }

  // Apply weight surcharge
  let weightCharge = 0;
  if (totalWeight > 50) {
    weightCharge = (totalWeight - 50) * 0.75;
  } else if (totalWeight > 20) {
    weightCharge = (totalWeight - 20) * 0.50;
  } else if (totalWeight > 5) {
    weightCharge = (totalWeight - 5) * 0.25;
  }

  // Apply service tier multiplier
  let tierMultiplier;
  if (order.serviceTier === 'express') {
    tierMultiplier = 2.5;
  } else if (order.serviceTier === 'priority') {
    tierMultiplier = 1.5;
  } else {
    tierMultiplier = 1.0;
  }

  let total = (baseRate + weightCharge) * tierMultiplier;

  // Apply promo discount
  if (order.promoCode === 'FREESHIP') {
    total = 0;
  } else if (order.promoCode === 'HALF') {
    total = total * 0.5;
  }

  return { total: Math.round(total * 100) / 100, weight: totalWeight, zone: order.destination.zone };
}
