Refactor this PaymentService to use the Strategy pattern. Currently, adding a new payment method requires modifying the processPayment method. The goal is to make it open for extension (new payment methods) without modifying existing code.

```typescript
class PaymentService {
  processPayment(order: Order, method: string, details: PaymentDetails): PaymentResult {
    let result: PaymentResult;

    switch (method) {
      case 'credit_card':
        if (!details.cardNumber || !details.expiry || !details.cvv) {
          throw new Error('Missing credit card details');
        }
        const cardValid = this.luhnCheck(details.cardNumber);
        if (!cardValid) throw new Error('Invalid card number');
        if (this.isExpired(details.expiry)) throw new Error('Card expired');
        result = this.chargeCreditCard(details.cardNumber, details.cvv, order.total);
        result.fee = order.total * 0.029 + 0.30;
        break;

      case 'paypal':
        if (!details.email) throw new Error('Missing PayPal email');
        const paypalToken = this.getPayPalToken(details.email);
        result = this.chargePayPal(paypalToken, order.total);
        result.fee = order.total * 0.034 + 0.49;
        break;

      case 'bank_transfer':
        if (!details.routingNumber || !details.accountNumber) {
          throw new Error('Missing bank details');
        }
        result = this.initiateBankTransfer(details.routingNumber, details.accountNumber, order.total);
        result.fee = Math.min(order.total * 0.01, 5.00);
        result.pendingDays = 3;
        break;

      case 'crypto':
        if (!details.walletAddress) throw new Error('Missing wallet address');
        if (!details.cryptoCurrency) throw new Error('Missing cryptocurrency type');
        const exchangeRate = this.getCryptoExchangeRate(details.cryptoCurrency);
        const cryptoAmount = order.total / exchangeRate;
        result = this.chargeCrypto(details.walletAddress, cryptoAmount, details.cryptoCurrency);
        result.fee = order.total * 0.01;
        result.cryptoAmount = cryptoAmount;
        break;

      default:
        throw new Error(`Unsupported payment method: ${method}`);
    }

    result.orderId = order.id;
    result.method = method;
    result.amount = order.total;
    result.timestamp = new Date();

    this.saveTransaction(result);
    return result;
  }

  // ... helper methods: luhnCheck, isExpired, chargeCreditCard, getPayPalToken, chargePayPal,
  //     initiateBankTransfer, getCryptoExchangeRate, chargeCrypto, saveTransaction
}
