class UserAnalytics:
    def __init__(self, db_connection):
        self.db = db_connection

    def get_user_tier(self, user):
        total_spent = 0
        for order in user.orders:
            if order.status == 'completed':
                for item in order.items:
                    total_spent += item.price * item.quantity
                total_spent -= order.discount

        if total_spent > 10000:
            return 'platinum'
        elif total_spent > 5000:
            return 'gold'
        elif total_spent > 1000:
            return 'silver'
        else:
            return 'bronze'

    def get_user_preferred_categories(self, user):
        category_counts = {}
        for order in user.orders:
            if order.status == 'completed':
                for item in order.items:
                    cat = item.category
                    category_counts[cat] = category_counts.get(cat, 0) + item.quantity

        sorted_cats = sorted(category_counts.items(), key=lambda x: x[1], reverse=True)
        return [cat for cat, count in sorted_cats[:5]]

    def get_user_avg_order_value(self, user):
        completed = [o for o in user.orders if o.status == 'completed']
        if not completed:
            return 0
        total = sum(
            sum(item.price * item.quantity for item in o.items) - o.discount
            for o in completed
        )
        return total / len(completed)

    def get_order_profit_margin(self, order):
        revenue = sum(item.price * item.quantity for item in order.items) - order.discount
        cost = sum(item.cost * item.quantity for item in order.items) + order.shipping_cost
        if revenue == 0:
            return 0
        return (revenue - cost) / revenue

    def is_order_high_value(self, order):
        total = sum(item.price * item.quantity for item in order.items) - order.discount
        return total > 500

    def get_user_lifetime_value(self, user):
        tier = self.get_user_tier(user)
        avg_order = self.get_user_avg_order_value(user)
        completed_count = len([o for o in user.orders if o.status == 'completed'])

        tier_multipliers = {'platinum': 1.5, 'gold': 1.3, 'silver': 1.1, 'bronze': 1.0}
        projected_annual_orders = (completed_count / max(user.account_age_months, 1)) * 12

        return avg_order * projected_annual_orders * tier_multipliers.get(tier, 1.0) * 3
