These three export classes share the same algorithmic structure (validate, transform, format, write) but differ in their formatting and writing steps. Refactor using the Template Method pattern to eliminate the duplicated structure while preserving each format's unique behavior.

```java
public class CsvExporter {
    public void export(List<Record> records, String outputPath) {
        // Validate
        if (records == null || records.isEmpty()) {
            throw new IllegalArgumentException("Records cannot be empty");
        }
        if (outputPath == null || outputPath.trim().isEmpty()) {
            throw new IllegalArgumentException("Output path is required");
        }

        // Transform: filter and sort
        List<Record> filtered = records.stream()
            .filter(r -> r.isActive())
            .sorted(Comparator.comparing(Record::getTimestamp))
            .collect(Collectors.toList());

        // Format as CSV
        StringBuilder sb = new StringBuilder();
        sb.append(String.join(",", getHeaders(filtered.get(0)))).append("\n");
        for (Record r : filtered) {
            sb.append(String.join(",", getValues(r))).append("\n");
        }
        String content = sb.toString();

        // Write to file
        Files.writeString(Path.of(outputPath + ".csv"), content);
        log.info("Exported {} records to CSV: {}", filtered.size(), outputPath);
    }
}

public class JsonExporter {
    public void export(List<Record> records, String outputPath) {
        // Validate (identical)
        if (records == null || records.isEmpty()) {
            throw new IllegalArgumentException("Records cannot be empty");
        }
        if (outputPath == null || outputPath.trim().isEmpty()) {
            throw new IllegalArgumentException("Output path is required");
        }

        // Transform: filter and sort (identical)
        List<Record> filtered = records.stream()
            .filter(r -> r.isActive())
            .sorted(Comparator.comparing(Record::getTimestamp))
            .collect(Collectors.toList());

        // Format as JSON
        ObjectMapper mapper = new ObjectMapper();
        mapper.enable(SerializationFeature.INDENT_OUTPUT);
        String content = mapper.writeValueAsString(filtered);

        // Write to file
        Files.writeString(Path.of(outputPath + ".json"), content);
        log.info("Exported {} records to JSON: {}", filtered.size(), outputPath);
    }
}

public class XmlExporter {
    public void export(List<Record> records, String outputPath) {
        // Validate (identical)
        if (records == null || records.isEmpty()) {
            throw new IllegalArgumentException("Records cannot be empty");
        }
        if (outputPath == null || outputPath.trim().isEmpty()) {
            throw new IllegalArgumentException("Output path is required");
        }

        // Transform: filter and sort (identical)
        List<Record> filtered = records.stream()
            .filter(r -> r.isActive())
            .sorted(Comparator.comparing(Record::getTimestamp))
            .collect(Collectors.toList());

        // Format as XML
        StringBuilder sb = new StringBuilder();
        sb.append("<?xml version=\"1.0\"?>\n<records>\n");
        for (Record r : filtered) {
            sb.append("  <record>\n");
            for (Map.Entry<String, Object> field : r.getFields().entrySet()) {
                sb.append(String.format("    <%s>%s</%s>\n", field.getKey(), field.getValue(), field.getKey()));
            }
            sb.append("  </record>\n");
        }
        sb.append("</records>");
        String content = sb.toString();

        // Write to file
        Files.writeString(Path.of(outputPath + ".xml"), content);
        log.info("Exported {} records to XML: {}", filtered.size(), outputPath);
    }
}
