Refactor this 300-line God Class that handles user management, authentication, email notifications, audit logging, and rate limiting — all in a single class. Decompose into focused, cohesive classes while maintaining the same external behavior.

```python
class UserManager:
    def __init__(self, db, cache, smtp_client, config):
        self.db = db
        self.cache = cache
        self.smtp = smtp_client
        self.config = config
        self._rate_limits = {}  # ip -> (count, window_start)

    # ---- User CRUD ----
    def create_user(self, email, password, name):
        if self._is_rate_limited(email):
            self._log_audit('CREATE_USER_RATE_LIMITED', {'email': email})
            raise RateLimitError('Too many attempts')
        if self.db.users.find_one({'email': email}):
            raise DuplicateError(f'User {email} already exists')
        hashed = self._hash_password(password)
        user = {'email': email, 'password': hashed, 'name': name, 'created_at': datetime.utcnow(), 'is_active': True, 'failed_logins': 0, 'locked_until': None}
        user_id = self.db.users.insert_one(user).inserted_id
        self.cache.delete(f'user_count')
        self._log_audit('USER_CREATED', {'user_id': str(user_id), 'email': email})
        self._send_welcome_email(email, name)
        return str(user_id)

    def get_user(self, user_id):
        cached = self.cache.get(f'user:{user_id}')
        if cached:
            return cached
        user = self.db.users.find_one({'_id': ObjectId(user_id)})
        if user:
            self.cache.set(f'user:{user_id}', user, ttl=300)
        return user

    def update_user(self, user_id, updates):
        allowed = {'name', 'email', 'preferences'}
        filtered = {k: v for k, v in updates.items() if k in allowed}
        self.db.users.update_one({'_id': ObjectId(user_id)}, {'$set': filtered})
        self.cache.delete(f'user:{user_id}')
        self._log_audit('USER_UPDATED', {'user_id': user_id, 'fields': list(filtered.keys())})

    def delete_user(self, user_id):
        user = self.get_user(user_id)
        if not user:
            raise NotFoundError(f'User {user_id} not found')
        self.db.users.delete_one({'_id': ObjectId(user_id)})
        self.cache.delete(f'user:{user_id}')
        self.cache.delete('user_count')
        self._log_audit('USER_DELETED', {'user_id': user_id, 'email': user['email']})
        self._send_account_deleted_email(user['email'], user['name'])

    # ---- Authentication ----
    def authenticate(self, email, password):
        if self._is_rate_limited(email):
            self._log_audit('AUTH_RATE_LIMITED', {'email': email})
            raise RateLimitError('Too many login attempts')
        user = self.db.users.find_one({'email': email})
        if not user:
            self._log_audit('AUTH_FAILED_NO_USER', {'email': email})
            raise AuthError('Invalid credentials')
        if user.get('locked_until') and user['locked_until'] > datetime.utcnow():
            self._log_audit('AUTH_LOCKED', {'email': email})
            raise AuthError('Account is locked')
        if not self._verify_password(password, user['password']):
            fails = user.get('failed_logins', 0) + 1
            update = {'failed_logins': fails}
            if fails >= self.config.max_failed_logins:
                update['locked_until'] = datetime.utcnow() + timedelta(minutes=self.config.lockout_minutes)
                self._send_account_locked_email(user['email'], user['name'])
            self.db.users.update_one({'_id': user['_id']}, {'$set': update})
            self._log_audit('AUTH_FAILED', {'email': email, 'failed_count': fails})
            raise AuthError('Invalid credentials')
        self.db.users.update_one({'_id': user['_id']}, {'$set': {'failed_logins': 0, 'last_login': datetime.utcnow()}})
        token = self._generate_token(user)
        self.cache.set(f'session:{token}', str(user['_id']), ttl=self.config.session_ttl)
        self._log_audit('AUTH_SUCCESS', {'user_id': str(user['_id'])})
        return token

    def logout(self, token):
        user_id = self.cache.get(f'session:{token}')
        self.cache.delete(f'session:{token}')
        if user_id:
            self._log_audit('LOGOUT', {'user_id': user_id})

    def reset_password(self, email):
        user = self.db.users.find_one({'email': email})
        if not user:
            return  # Don't reveal user existence
        token = self._generate_reset_token()
        self.cache.set(f'reset:{token}', str(user['_id']), ttl=3600)
        self._send_reset_email(email, user['name'], token)
        self._log_audit('PASSWORD_RESET_REQUESTED', {'email': email})

    # ---- Password Helpers ----
    def _hash_password(self, password):
        salt = bcrypt.gensalt(rounds=12)
        return bcrypt.hashpw(password.encode(), salt)

    def _verify_password(self, password, hashed):
        return bcrypt.checkpw(password.encode(), hashed)

    def _generate_token(self, user):
        return jwt.encode({'user_id': str(user['_id']), 'exp': datetime.utcnow() + timedelta(seconds=self.config.session_ttl)}, self.config.jwt_secret)

    def _generate_reset_token(self):
        return secrets.token_urlsafe(32)

    # ---- Email ----
    def _send_welcome_email(self, email, name):
        self.smtp.send(to=email, subject='Welcome!', body=f'Hello {name}, welcome to our platform!')

    def _send_account_deleted_email(self, email, name):
        self.smtp.send(to=email, subject='Account Deleted', body=f'{name}, your account has been deleted.')

    def _send_account_locked_email(self, email, name):
        self.smtp.send(to=email, subject='Account Locked', body=f'{name}, your account has been locked due to too many failed login attempts.')

    def _send_reset_email(self, email, name, token):
        self.smtp.send(to=email, subject='Password Reset', body=f'{name}, use this link to reset: /reset?token={token}')

    # ---- Rate Limiting ----
    def _is_rate_limited(self, key):
        now = time.time()
        if key in self._rate_limits:
            count, window_start = self._rate_limits[key]
            if now - window_start < self.config.rate_limit_window:
                if count >= self.config.rate_limit_max:
                    return True
                self._rate_limits[key] = (count + 1, window_start)
            else:
                self._rate_limits[key] = (1, now)
        else:
            self._rate_limits[key] = (1, now)
        return False

    # ---- Audit ----
    def _log_audit(self, action, details):
        self.db.audit_log.insert_one({'action': action, 'details': details, 'timestamp': datetime.utcnow()})
