// order.service.ts
import { InventoryService } from './inventory.service';

export class OrderService {
  constructor(
    private inventory: InventoryService,
    private db: Database
  ) {}

  async createOrder(userId: string, items: OrderItem[]): Promise<Order> {
    // Check inventory for all items
    for (const item of items) {
      const available = await this.inventory.checkStock(item.sku, item.quantity);
      if (!available) {
        throw new InsufficientStockError(item.sku);
      }
    }

    // Reserve inventory
    const reservations = await this.inventory.reserveItems(
      items.map(i => ({ sku: i.sku, quantity: i.quantity }))
    );

    // Create order record
    const order = await this.db.orders.create({
      userId,
      items,
      reservations: reservations.map(r => r.id),
      status: 'pending',
      total: items.reduce((sum, i) => sum + i.price * i.quantity, 0),
      createdAt: new Date()
    });

    return order;
  }

  async cancelOrder(orderId: string): Promise<void> {
    const order = await this.db.orders.findById(orderId);
    if (!order) throw new NotFoundError('Order');
    if (order.status === 'shipped') throw new InvalidStateError('Cannot cancel shipped order');

    // Release inventory reservations
    await this.inventory.releaseReservations(order.reservations);

    order.status = 'cancelled';
    order.cancelledAt = new Date();
    await this.db.orders.update(order);
  }

  // Called by NotificationService to get order details for emails
  async getOrderForNotification(orderId: string): Promise<OrderNotificationData> {
    const order = await this.db.orders.findById(orderId);
    const user = await this.db.users.findById(order.userId);
    return {
      orderId: order.id,
      userEmail: user.email,
      userName: user.name,
      items: order.items,
      total: order.total,
      status: order.status
    };
  }
}

// inventory.service.ts
import { NotificationService } from './notification.service';

export class InventoryService {
  constructor(
    private notifications: NotificationService,
    private db: Database
  ) {}

  async checkStock(sku: string, quantity: number): Promise<boolean> {
    const product = await this.db.products.findBySku(sku);
    return product ? product.availableQuantity >= quantity : false;
  }

  async reserveItems(items: { sku: string; quantity: number }[]): Promise<Reservation[]> {
    const reservations: Reservation[] = [];
    for (const item of items) {
      const product = await this.db.products.findBySku(item.sku);
      product.availableQuantity -= item.quantity;
      product.reservedQuantity += item.quantity;
      await this.db.products.update(product);

      const reservation = await this.db.reservations.create({
        sku: item.sku,
        quantity: item.quantity,
        expiresAt: new Date(Date.now() + 30 * 60 * 1000)
      });
      reservations.push(reservation);

      // Notify if stock is low
      if (product.availableQuantity <= product.reorderThreshold) {
        await this.notifications.sendLowStockAlert(product);
      }
    }
    return reservations;
  }

  async releaseReservations(reservationIds: string[]): Promise<void> {
    for (const id of reservationIds) {
      const reservation = await this.db.reservations.findById(id);
      if (reservation) {
        const product = await this.db.products.findBySku(reservation.sku);
        product.availableQuantity += reservation.quantity;
        product.reservedQuantity -= reservation.quantity;
        await this.db.products.update(product);
        await this.db.reservations.delete(id);

        // Notify that stock is replenished
        await this.notifications.sendStockReplenishedAlert(product);
      }
    }
  }
}

