Refactor this legacy data ingestion pipeline class. It has multiple overlapping code smells: Long Methods (process_batch is 90+ lines), duplicated parsing logic, Primitive Obsession (status strings, error codes as ints), Switch Statements on record type, and tight coupling to external systems. Target: reduce overall cyclomatic complexity by at least 40% and eliminate all duplication.

```python
class DataPipeline:
    def __init__(self, source_db, target_db, error_queue, metrics_client):
        self.source = source_db
        self.target = target_db
        self.errors = error_queue
        self.metrics = metrics_client

    def process_batch(self, batch_id):
        batch = self.source.get_batch(batch_id)
        if not batch:
            self.metrics.increment('pipeline.batch_not_found')
            return {'status': 'error', 'code': 404, 'message': 'Batch not found'}

        if batch['status'] != 'pending':
            self.metrics.increment('pipeline.invalid_batch_status')
            return {'status': 'error', 'code': 409, 'message': f"Batch is {batch['status']}, expected pending"}

        self.source.update_batch_status(batch_id, 'processing')
        self.metrics.increment('pipeline.batch_started')

        results = {'processed': 0, 'failed': 0, 'skipped': 0}
        errors_list = []

        for record in batch['records']:
            try:
                # Parse based on record type (duplicated validation)
                if record['type'] == 'user':
                    if not record.get('email'):
                        results['skipped'] += 1
                        errors_list.append({'record_id': record['id'], 'error': 'Missing email', 'code': 1001})
                        continue
                    if not record.get('name'):
                        results['skipped'] += 1
                        errors_list.append({'record_id': record['id'], 'error': 'Missing name', 'code': 1002})
                        continue
                    if record.get('email') and '@' not in record['email']:
                        results['skipped'] += 1
                        errors_list.append({'record_id': record['id'], 'error': 'Invalid email format', 'code': 1003})
                        continue
                    parsed = {
                        'table': 'users',
                        'data': {
                            'email': record['email'].strip().lower(),
                            'name': record['name'].strip(),
                            'phone': record.get('phone', '').strip(),
                            'created_at': record.get('created_at', datetime.utcnow().isoformat())
                        }
                    }
                elif record['type'] == 'order':
                    if not record.get('user_id'):
                        results['skipped'] += 1
                        errors_list.append({'record_id': record['id'], 'error': 'Missing user_id', 'code': 2001})
                        continue
                    if not record.get('items') or len(record['items']) == 0:
                        results['skipped'] += 1
                        errors_list.append({'record_id': record['id'], 'error': 'Missing items', 'code': 2002})
                        continue
                    if record.get('total') is not None and record['total'] < 0:
                        results['skipped'] += 1
                        errors_list.append({'record_id': record['id'], 'error': 'Negative total', 'code': 2003})
                        continue
                    total = record.get('total', sum(i.get('price', 0) * i.get('qty', 0) for i in record['items']))
                    parsed = {
                        'table': 'orders',
                        'data': {
                            'user_id': record['user_id'],
                            'items': record['items'],
                            'total': total,
                            'currency': record.get('currency', 'USD'),
                            'ordered_at': record.get('ordered_at', datetime.utcnow().isoformat())
                        }
                    }
                elif record['type'] == 'product':
                    if not record.get('sku'):
                        results['skipped'] += 1
                        errors_list.append({'record_id': record['id'], 'error': 'Missing SKU', 'code': 3001})
                        continue
                    if not record.get('name'):
                        results['skipped'] += 1
                        errors_list.append({'record_id': record['id'], 'error': 'Missing product name', 'code': 3002})
                        continue
                    if record.get('price') is not None and record['price'] < 0:
                        results['skipped'] += 1
                        errors_list.append({'record_id': record['id'], 'error': 'Negative price', 'code': 3003})
                        continue
                    parsed = {
                        'table': 'products',
                        'data': {
                            'sku': record['sku'].strip().upper(),
                            'name': record['name'].strip(),
                            'price': record.get('price', 0),
                            'category': record.get('category', 'uncategorized'),
                            'updated_at': record.get('updated_at', datetime.utcnow().isoformat())
                        }
                    }
                else:
                    results['skipped'] += 1
                    errors_list.append({'record_id': record['id'], 'error': f"Unknown type: {record['type']}", 'code': 9001})
                    continue

                # Write to target (same for all types)
                self.target.upsert(parsed['table'], parsed['data'])
                results['processed'] += 1
                self.metrics.increment(f"pipeline.record_processed.{record['type']}")

            except Exception as e:
                results['failed'] += 1
                errors_list.append({'record_id': record.get('id', 'unknown'), 'error': str(e), 'code': 9999})
                self.metrics.increment('pipeline.record_failed')

        # Finalize batch
        if results['failed'] > 0:
            final_status = 'completed_with_errors'
        elif results['skipped'] > 0:
            final_status = 'completed_with_warnings'
        else:
            final_status = 'completed'

        self.source.update_batch_status(batch_id, final_status)

        if errors_list:
            self.errors.publish({'batch_id': batch_id, 'errors': errors_list})

        self.metrics.gauge('pipeline.batch_processed', results['processed'])
        self.metrics.gauge('pipeline.batch_failed', results['failed'])
        self.metrics.gauge('pipeline.batch_skipped', results['skipped'])

        return {'status': final_status, 'code': 200, 'results': results, 'error_count': len(errors_list)}
